module fsm #(
    parameter s0 = 3'b000,
    parameter s1 = 3'b001,
    parameter s2 = 3'b010,
    parameter s3 = 3'b011,
    parameter s4 = 3'b100,
    parameter s5 = 3'b101
) (
    input IN,
    output reg MATCH,
    input CLK,
    input RST
);
    reg [2:0] state, next_state;
    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            state <= s0;
            MATCH <= 1'b0;
        end
        else begin
            state <= next_state;
        end
    end
    always @(*) begin
        case (state)
            s0: begin
                if (IN) begin
                    next_state = s1;
                end
                else begin
                    next_state = s0;
                end
                MATCH = 1'b0;
            end
            s1: begin
                if (IN) begin
                    next_state = s1;
                end
                else begin
                    next_state = s2;
                end
                MATCH = 1'b0;
            end
            s2: begin
                if (IN) begin
                    next_state = s1;
                end
                else begin
                    next_state = s3;
                end
                MATCH = 1'b0;
            end
            s3: begin
                if (IN) begin
                    next_state = s1;
                end
                else begin
                    next_state = s4;
                end
                MATCH = 1'b0;
            end
            s4: begin
                if (IN) begin
                    next_state = s5;
                end
                else begin
                    next_state = s0;
                end
                MATCH = 1'b0;
            end
            s5: begin
                if (IN) begin
                    next_state = s1;
                end
                else begin
                    next_state = s2;
                end
                MATCH = 1'b0;
            end
            default: begin
                next_state = s0;
                MATCH = 1'b0;
            end
        endcase
    end
endmodule
